            DefineSection("Scripts", async() => {
                WriteLiteral(@"
    <script>
        const token = document.querySelector('#antiForgeryForm input[name=""__RequestVerificationToken""]').value;
        let mpesaModalInstance = null;

        function payCash(loanId) {
            if (!confirm(""Record this fine as paid by cash?"")) return;

            fetch('/Fine/PayCash', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
                    'RequestVerificationToken': token
                },
                body: `loanId=${loanId}`
            })
                .then(response => response.json())
                .then(data => {
                    alert(data.message);
                    if (data.success) {
                        location.reload();
                    }
                })
                .catch(() => alert('An error occurred while recording cash payment.'));
        }

        function openMpesaModal(loanId, studentName) {
        ");
                WriteLiteral(@"    document.getElementById('mpesaLoanId').value = loanId;
            document.getElementById('mpesaStudentName').value = studentName || '';
            document.getElementById('mpesaPhoneNumber').value = '';

            const modalElement = document.getElementById('mpesaModal');
            mpesaModalInstance = new bootstrap.Modal(modalElement);
            mpesaModalInstance.show();
        }

        function submitMpesaPayment() {
            const loanId = document.getElementById('mpesaLoanId').value;
            const phoneNumber = document.getElementById('mpesaPhoneNumber').value.trim();

            if (!phoneNumber) {
                alert('Please enter a phone number.');
                return;
            }

            fetch('/Fine/InitiateMpesa', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
                    'RequestVerificationToken': token
                },
      ");
                WriteLiteral(@"          body: `loanId=${encodeURIComponent(loanId)}&phoneNumber=${encodeURIComponent(phoneNumber)}`
            })
                .then(response => response.json())
                .then(data => {
                    alert(data.message);
                    if (data.success) {
                        if (mpesaModalInstance) {
                            mpesaModalInstance.hide();
                        }
                        location.reload();
                    }
                })
                .catch(() => alert('An error occurred while initiating M-Pesa.'));
        }

        new DataTable('#finesTable', {
            layout: {
                topStart: {
                    buttons: ['copy', 'csv', 'excel', 'pdf', 'print']
                }
            },
            language: {
                emptyTable: ""No fines found.""
            }
        });
    </script>
");
            }
            );
        }
